local UITip = class("UITip", IGUILayout)

SelectLeftOrRight={
    Left = 1,
    Right = 2,
}

function UITip:onLoad()

    self:initUI()
    self:initEvent()
    self:initIconAndTitle()
    self.selectMode = SelectLeftOrRight.Left
    self:onClickLift()

end

function UITip:initUI()

    self.tvTitleText = self:getChildWindow("LiftingSimulatorTip-Title-Text" , GUIType.StaticText)
    self.tvTitleText:SetText(Lang:getString("LiftingSimulatorTip-Title-Text"))

    self.ivLiftOptionBg = self:getChildWindow("LiftingSimulatorTip-Content-LiftOptionBg",GUIType.StaticImage)
    self.tvLiftOptionTitle  = self:getChildWindow("LiftingSimulatorTip-Content-LiftOptionTitle" ,GUIType.StaticText)
    self.ivLiftOptionIcon  = self:getChildWindow("LiftingSimulatorTip-Content-LiftOptionIcon" , GUIType.StaticImage)
    self.ivLiftOptionCheckBg  = self:getChildWindow("LiftingSimulatorTip-Content-LiftOptionCheckBg",GUIType.StaticImage)
    self.ivLiftOptionCheck = self:getChildWindow("LiftingSimulatorTip-Content-LiftOptionCheckList",GUIType.StaticImage)

    self.ivRightOptionBg = self:getChildWindow("LiftingSimulatorTip-Content-RightOptionBg",GUIType.StaticImage)
    self.tvRightOptionTitle  = self:getChildWindow("LiftingSimulatorTip-Content-RightOptionTitle" ,GUIType.StaticText)
    self.ivRightOptionIcon  = self:getChildWindow("LiftingSimulatorTip-Content-RightOptionIcon" , GUIType.StaticImage)
    self.ivRightOptionCheckBg  = self:getChildWindow("LiftingSimulatorTip-Content-RightOptionCheckBg",GUIType.StaticImage)
    self.ivRightOptionCheck = self:getChildWindow("LiftingSimulatorTip-Content-RightOptionCheckList",GUIType.StaticImage)

    self.tvContentTips  = self:getChildWindow("LiftingSimulatorTip-Content-Tips" ,GUIType.StaticText)
    self.tvContentTips:SetText(Lang:getString("LiftingSimulatorTip-Title-Tip"))
    self.btnContentButton  = self:getChildWindow("LiftingSimulatorTip-Content-Button" ,GUIType.Button)

    self.btnContentButton:SetText(Lang:getString("GUITip_Determine"))

end

function UITip:initEvent()

    self.ivLiftOptionBg:registerEvent(GUIEvent.Click,function ()
        self:onClickLift()
    end)

    self.ivLiftOptionCheckBg:registerEvent(GUIEvent.Click, function ()
        self:onClickLift()
    end)

    self.ivRightOptionBg:registerEvent(GUIEvent.Click, function ()
        self:onClickRight()
    end)

    self.ivRightOptionCheckBg:registerEvent(GUIEvent.Click, function ()
        self:onClickRight()
    end)
    self.btnContentButton:registerEvent(GUIEvent.ButtonClick,function ()
        self:onClickButton()
    end)

    self:registerEvent(TipItemShowEvent,function ()
        GUIManager:addShowQueue(GUITip)
    end)
end

function UITip:initIconAndTitle()

    local sex = PlayerManager:getClientPlayer():getSex()
    --print("+++++++++++++++++++sex  "..sex)
    --sex = 2
    if sex == 1 then --男

        self.tvLiftOptionTitle:SetText(Lang:getString("LiftingSimulatorTip-Default-Boy"))
        self.ivLiftOptionIcon:SetImage("set:LiftingSimulatorTip1.json image:boy1")

        local oneSkin = SkinConfig:getSkinById(GameConfig.boyFreeSkinId)

        if oneSkin then
            self.tvRightOptionTitle:SetText(Lang:getString(oneSkin.Name))
            self.ivRightOptionIcon:SetImage(oneSkin.Icon)
        end


    else --女

        self.tvLiftOptionTitle:SetText(Lang:getString("LiftingSimulatorTip-Default-Girl"))
        self.ivLiftOptionIcon:SetImage("set:LiftingSimulatorTip1.json image:girl1")

        local oneSkin = SkinConfig:getSkinById(GameConfig.girlFreeSkinId)
        if oneSkin then
            self.tvRightOptionTitle:SetText(Lang:getString(oneSkin.Name))
            self.ivRightOptionIcon:SetImage(oneSkin.Icon)
        end

    end

end
function UITip:onClickLift()

    self.ivLiftOptionBg:SetImage("set:LiftingSimulatorTip1.json image:bg5")
    self.ivLiftOptionCheck:SetVisible(true)

    self.ivRightOptionBg:SetImage("set:LiftingSimulatorTip1.json image:bg4")
    self.ivRightOptionCheck:SetVisible(false)
    self.selectMode = SelectLeftOrRight.Left

end

function UITip:onClickRight()

    self.ivLiftOptionBg:SetImage("set:LiftingSimulatorTip1.json image:bg4")
    self.ivLiftOptionCheck:SetVisible(false)

    self.ivRightOptionBg:SetImage("set:LiftingSimulatorTip1.json image:bg5")
    self.ivRightOptionCheck:SetVisible(true)
    self.selectMode = SelectLeftOrRight.Right

end

function UITip:onClickButton()

    if self.selectMode == SelectLeftOrRight.Left then
        local data = DataBuilder.new():addParam("index", Define.SelectSkinType.Default):getData()
        PacketSender:sendLuaCommonData("SelectSkin", data)
    else
        local data = DataBuilder.new():addParam("index", Define.SelectSkinType.Free):getData()
         PacketSender:sendLuaCommonData("SelectSkin", data)
    end

    self:hide()

    self.taskFinished = true
    LogUtil.log("UITip:onClickButton taskFinished")
end

return UITip
